package tests;import base.BaseTestPlaywright;import org.junit.jupiter.api.Test;import java.nio.file.Paths;import static org.junit.jupiter.api.Assertions.assertTrue;public class HP02SeccionesCocineroPlaywrightTest extends BaseTestPlaywright {    @Test    void panelCocineroDistingueSecciones() {        page.navigate("https://ernest.xo.je/index.php?route=auth/login");        page.locator("input[name='username']").fill("cocinero");        page.locator("input[name='password']").fill("123");        page.locator("button[type='submit']").click();        page.waitForTimeout(2000);        assertTrue(                page.content().contains("Pedidos Pendientes"),                "No se visualiza la sección Pedidos Pendientes."        );        assertTrue(                page.content().contains("Pedidos en Preparación"),                "No se visualiza la sección Pedidos en Preparación."        );        page.screenshot(new com.microsoft.playwright.Page.ScreenshotOptions()                .setPath(Paths.get("evidencias/HP02-secciones-cocinero.png"))                .setFullPage(true));    }}